// SPDX-License-Identifier: GPL-3.0
pragma solidity >=0.8.3;

library NewsValidation {
    function validatorsCount(address[] storage validators) external view returns (uint256) {
        return validators.length;
    }

    function isValidator(address[] storage validators, address target) external view returns (bool) {
        for (uint256 i = 0; i < validators.length; i++) {
            if (validators[i] == target) {
                return true;
            }
        }
        return false;
    }
}

contract NewsManager {
    
}

